import React from 'react';
import { categories } from '../data/products';
import './CategoryGrid.css';

import phone from '../assets/images/phone.jpg';
import laptop from '../assets/images/laptop.jpg';
import headphone from '../assets/images/headphone.jpg';
import tv from '../assets/images/tv.jpg';
import cookware from '../assets/images/cookware.jpg';
import chair from '../assets/images/chair.jpg';
import decor from '../assets/images/decor.jpg';
import appliances from '../assets/images/appliances.jpg';
import menswear from '../assets/images/menwear.jpg';
import footwear from '../assets/images/footwear.jpg';
import handbags from '../assets/images/handbags.jpg';
import sunglasses from '../assets/images/sunglasses.jpg';
import notebooks from '../assets/images/notebooks.jpg';
import pens from '../assets/images/pens.jpg';
import art_supplies from '../assets/images/art_supplies.jpg';

const imageMap = {
  'Smartphones': phone,
  'Laptops': laptop,
  'Headphones': headphone,
  'Smart TVs': tv,
  'Cookware': cookware,
  'Furniture': chair,
  'Décor': decor,
  'Appliances': appliances,
  'Men\'s Wear': menswear,
  'Footwear': footwear,
  'Handbags': handbags,
  'Sunglasses': sunglasses,
  'Notebooks': notebooks,
  'Pens': pens,
  'Art Supplies': art_supplies
};

export default function CategoryGrid() {
  return (
    <section className="cat-section">
      <div className="cat-grid">
        {categories.map(cat => (
          <div className="cat-card" key={cat.title}>
            <h3 className="cat-card__title">{cat.title}</h3>
            <div className="cat-card__items">
              {cat.items.map(item => (
                <div className="cat-card__item" key={item.label}>
                  <div className="cat-card__img">
                    <img src={imageMap[cat.title]} alt={item.label} />
                  </div>
                  <span className="cat-card__label">{item.label}</span>
                </div>
              ))}
            </div>
            <button className="cat-card__link">See all deals →</button>
          </div>
        ))}
      </div>
    </section>
  );
}
